const task = $('Normalize Task Input').first().json;
let context = {};
try {
  context = JSON.parse(($json.stdout || '{}').trim());
} catch (e) {
  context = { parse_error: String(e) };
}

const codeCreationPrompt = [
  'Role: Code Creation Agent',
  'You are modifying an existing MultiScholarship platform.',
  'Constraints:',
  ...(task.constraints || []).map((c) => `- ${c}`),
  'Task Objective:',
  task.objective || '',
  'Required Output JSON keys:',
  '- changed_files: string[]',
  '- patch_diff: string (unified diff)',
  '- migration_sql: string|null',
  '- test_commands: string[]',
  '- risk_notes: string[]',
  'Use existing architecture and keep changes minimal and reversible.'
].join('\n');

const validationPrompt = [
  'Role: Validation Agent',
  'Validate generated patch for logic, behavior, and acceptance criteria.',
  'Acceptance Criteria:',
  ...((task.acceptance_criteria || []).map((c) => `- ${c}`)),
  'Required Output JSON keys:',
  '- pass: boolean',
  '- defects: array of {severity,file,issue,fix}',
  '- regression_risks: string[]',
  '- missing_tests: string[]'
].join('\n');

const securityPrompt = [
  'Role: Security Review Agent',
  'Check RBAC, input validation, CSRF, auth/session boundaries, secret exposure, and unsafe dependencies.',
  'Required Output JSON keys:',
  '- pass: boolean',
  '- findings: array of {severity,file,issue,fix}',
  '- blocked: boolean'
].join('\n');

const uiPrompt = [
  'Role: UI Error Fixing Agent',
  'Check responsive layout, accessibility, empty/loading/error states, and interaction defects.',
  'Required Output JSON keys:',
  '- pass: boolean',
  '- ui_issues: array of {severity,file,issue,fix}',
  '- css_or_markup_patch: string'
].join('\n');

return [{
  json: {
    ...task,
    repository_context: context,
    prompts: {
      code_creation: codeCreationPrompt,
      validation: validationPrompt,
      security: securityPrompt,
      ui: uiPrompt
    }
  }
}];

return [{
  json: {
    pass: false,
    reason: 'missing_AGENT_ORCHESTRATOR_URL',
    next_action: 'Configure AGENT_ORCHESTRATOR_URL env var in n8n and re-run.'
  }
}];

const payload = $json;
const changedFiles = payload.changed_files || [];
const patch = payload.patch_diff || '';
const valid = Array.isArray(changedFiles) && changedFiles.length > 0 && typeof patch === 'string' && patch.trim() !== '';
return [{ json: { ...payload, output_contract_ok: valid } }];

